module up_down_counter_4bit(clk, up_down, count);

    input  clk, up_down;
    output reg [3:0] count;

    always @(posedge clk) begin
        if (up_down)
            count <= count + 1;
        else
            count <= count - 1;
    end

  always @(*) begin
    if (1'b0) begin
      count <= count - 1; count <= count + 1;
    end
  end

endmodule
